import React, { useState } from 'react';
import { Trash2, ShoppingBag, AlertCircle, ArrowRight, Minus, Plus, Loader2 } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { URL_CARPETA_IMAGENES } from '../utils/helpers';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const Carrito = () => {
  const { cart, removeFromCart, updateQuantity, totalPrice, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [enviando, setEnviando] = useState(false);

  const handleFinalizarCompra = async () => {
    if (cart.length === 0 || enviando) return;

    setEnviando(true);
    try {
      // Preparamos los datos para el Backend
      const pedidoData = {
        clienteId: user.id || user._id, // Dependiendo de cómo lo guardes en el context
        items: cart,
        puntoEntrega: {
          direccion: user.direccion || "Dirección no especificada", // Lo ideal es que el user tenga esto en su perfil
          lat: 0,
          lng: 0
        }
      };

      // Enviamos a la nube
      const res = await axios.post(`${process.env.REACT_APP_API_URL}/api/pedidos`, pedidoData);

      if (res.status === 201) {
        alert("¡Pedido confirmado con éxito! Los locales han sido notificados.");
        clearCart();
        navigate('/'); // O a una página de "Mis Pedidos"
      }
    } catch (error) {
      console.error("Error al procesar pedido:", error);
      alert("Hubo un problema al procesar tu pedido. Intenta nuevamente.");
    } finally {
      setEnviando(false);
    }
  };

  if (cart.length === 0) {
    return (
      <div style={emptyContainer}>
        <div style={iconCircle}>
            <ShoppingBag size={48} color="#e67e22" />
        </div>
        <h3 style={{ color: '#1e293b', marginTop: '20px', marginBottom: '10px' }}>Tu carrito está vacío</h3>
        <p style={{ color: '#64748b', maxWidth: '250px' }}>¡Explora las mejores ofertas en la nube y llena tu bolsa!</p>
        <button 
          onClick={() => navigate('/')} 
          style={{ ...btnCheckout, width: 'auto', marginTop: '20px', padding: '12px 25px' }}
        >
          Volver a las ofertas
        </button>
      </div>
    );
  }

  return (
    <div style={wrapper}>
      <div style={container}>
        <div style={header}>
          <h2 style={{ margin: 0, fontSize: '1.4rem', color: '#1e293b' }}>Resumen de Pedido</h2>
          <button onClick={clearCart} style={btnClear}>Vaciar carrito</button>
        </div>

        <div style={listContainer}>
          {cart.map((item) => (
            <div key={item._id} style={cardItem}>
              <img 
                src={`${URL_CARPETA_IMAGENES}${item.publicId}.jpg`} 
                alt={item.producto} 
                style={imgThumb}
                onError={(e) => { e.target.src = "https://via.placeholder.com/150?text=Sin+Imagen"; }} 
              />
              <div style={{ flex: 1, marginLeft: '15px' }}>
                <h4 style={itemTitle}>{item.producto}</h4>
                <p style={itemLocal}>{item.local?.nombre || "Local Asociado"}</p>
                <div style={priceTag}>${item.precioNuevo}</div>
              </div>

              <div style={qtyControls}>
                <button onClick={() => updateQuantity(item._id, item.cantidad - 1)} style={qtyBtn}>
                  <Minus size={14} />
                </button>
                <span style={qtyText}>{item.cantidad}</span>
                <button onClick={() => updateQuantity(item._id, item.cantidad + 1)} style={qtyBtn}>
                  <Plus size={14} />
                </button>
              </div>

              <button 
                onClick={() => removeFromCart(item._id)} 
                style={btnDelete}
                title="Quitar producto"
              >
                <Trash2 size={18} />
              </button>
            </div>
          ))}
        </div>

        <div style={footer}>
          <div style={resumenRow}>
            <span>Subtotal</span>
            <span style={valText}>${totalPrice}</span>
          </div>
          <div style={resumenRow}>
            <span>Envío domicilio</span>
            <span style={{ color: '#27ae60', fontWeight: 'bold' }}>¡GRATIS!</span>
          </div>
          <div style={divider} />
          <div style={totalRow}>
            <span>Total a pagar</span>
            <span>${totalPrice}</span>
          </div>

          <div style={infoBanner}>
            <AlertCircle size={18} color="#3182ce" />
            <small style={{lineHeight: '1.4'}}>
                Entrega en: <strong>{user?.direccion || "Seleccionar dirección"}</strong><br/>
                Pagás al recibir. Tené el efectivo listo.
            </small>
          </div>

          <button 
            onClick={handleFinalizarCompra} 
            style={{...btnCheckout, opacity: enviando ? 0.7 : 1}}
            disabled={enviando}
          >
            {enviando ? (
                <>
                    <Loader2 size={20} className="animate-spin" /> Procesando...
                </>
            ) : (
                <>
                    Confirmar Pedido <ArrowRight size={20} />
                </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

// --- ESTILOS (Mantenidos y optimizados) ---
const wrapper = { padding: '20px', maxWidth: '600px', margin: '0 auto' };
const container = { background: 'white', borderRadius: '28px', padding: '30px', boxShadow: '0 20px 40px rgba(0,0,0,0.08)', border: '1px solid #f1f5f9' };
const iconCircle = { width: '100px', height: '100px', background: '#fff3e0', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' };
